WaitPlayerCountDownState = class("WaitPlayerCountDownState", GameState)

function WaitPlayerCountDownState:enter()
    self.GameStatus = Define.GameStatus.WaitPlayerCountDown

    self.countDownTime = ChampionShipConfig.waitPlayerCountDownTime
end

function WaitPlayerCountDownState:update()
    MsgSender.sendTopTips(1, IMessages:msgWaitPlayerEnough(self.countDownTime, IMessages.UNIT_SECOND, false))

    self.countDownTime = self.countDownTime - 1

    if self.countDownTime <= 0 then
        LogUtil.log("WaitPlayerCountDownState:update self.countDownTime <= 0")
        local maxPlayer = PlayerManager:getReadyPlayerCount()
        PlayerManager:setMaxPlayer(maxPlayer)
        HostApi.sendStartGame(maxPlayer)
        GameStateManager:changeState(Define.GameStatus.WaitGameStart)
    end
end

function WaitPlayerCountDownState:leave()
    --TODO
end

